/**
 *
 * @param instanceMap
 * @param selectionManager
 * @param selection
 * @constructor
 */
export function ApplyBrushOnMap(instanceMap, selectionManager, selection) {
    let eventManager = this,
        behaviours = eventManager.behaviours;

    if (selection && behaviours.PLOT_ZOOM) {
        let zoomInstance = behaviours.PLOT_ZOOM.instance,
            transform = zoomInstance.getTransform();

        instanceMap.instance.reset();
        zoomInstance.zoomToBounds(selection.map(b0 => transform.invert(b0)));
    }
}
